import { ViewTitle } from 'components/ViewTitle';
import React, { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import * as actions from '../../redux/actions';
import {
  Avatar,
  Card,
  Typography,
  Chip,
  Box,
  Divider,
  Grid,
  IconButton,
  Badge,
  ToggleButton,
  ToggleButtonGroup,
  List,
  ListItem,
  ListItemText,
  Stack,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
} from '@mui/material';
import {
  AccessTime as TimeIcon,
  Business as ProjectIcon,
  Phone as PhoneIcon,
  Work as WorkIcon,
  DateRange as DateIcon,
  AttachMoney as SalaryIcon,
  ChevronLeft,
  ChevronRight,
  CalendarMonth as CalendarIcon,
  ViewList as ViewListIcon,
  Login as LoginIcon,
  Logout as LogoutIcon,
  Schedule as OTIcon,
  Close as CloseIcon,
} from '@mui/icons-material';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction';
import dayjs from 'dayjs';
import 'dayjs/locale/th';

dayjs.locale('th');

export default function PersonalProfile({ title, subtitle }) {
  const dispatch = useDispatch();
  const me = useSelector((state) => state.me);
  const timestamp = useSelector((state) => state.timestamp);
  const project = useSelector((state) => state.project);
  const profile = me?.userData;

  const [viewMode, setViewMode] = useState('calendar');
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);

  useEffect(() => {
    dispatch(actions.meGet());
    dispatch(actions.timestampAll({ profile: profile?._id }));
    dispatch(actions.projectAll({ profile: profile?._id }));

    return () => {};
  }, []);

  const renderTitle = () => <ViewTitle title={title} subtitle={subtitle} />;

  const renderDetail = () => (
    <Card className="mb-4">
      <Box className="relative">
        <Box className="h-28 " />
        <Avatar
          src={profile?.image?.url}
          sx={{
            width: 120,
            height: 120,
            border: '4px solid white',
            position: 'absolute',
            bottom: -60,
            left: '50%',
            transform: 'translateX(-50%)',
          }}
        />
      </Box>
      <Box className="pt-16 pb-4 text-center">
        <Typography variant="h5" className="font-bold">
          {profile?.firstname} {profile?.lastname}
        </Typography>
        <Chip label={profile?.role?.name} color="primary" className="mt-2" />
      </Box>
      <Divider />
      <Grid container spacing={2} className="p-4">
        <Grid item xs={12} md={6}>
          <Box className="flex items-center gap-2">
            <PhoneIcon color="action" />
            <Box>
              <Typography variant="caption" color="textSecondary">
                เบอร์โทรศัพท์
              </Typography>
              <Typography>{profile?.phone_number || '-'}</Typography>
            </Box>
          </Box>
        </Grid>
        <Grid item xs={12} md={6}>
          <Box className="flex items-center gap-2">
            <WorkIcon color="action" />
            <Box>
              <Typography variant="caption" color="textSecondary">
                แผนก
              </Typography>
              <Typography>{profile?.department?.name || '-'}</Typography>
            </Box>
          </Box>
        </Grid>
        <Grid item xs={12} md={6}>
          <Box className="flex items-center gap-2">
            <SalaryIcon color="action" />
            <Box>
              <Typography variant="caption" color="textSecondary">
                เงินเดือน
              </Typography>
              <Typography>{profile?.salary?.month} บาท</Typography>
            </Box>
          </Box>
        </Grid>
        <Grid item xs={12} md={6}>
          <Box className="flex items-center gap-2">
            <DateIcon color="action" />
            <Box>
              <Typography variant="caption" color="textSecondary">
                วันที่เริ่มงาน
              </Typography>
              <Typography>
                {dayjs(profile?.start_date).format('DD/MM/YYYY') || '-'}
              </Typography>
            </Box>
          </Box>
        </Grid>
      </Grid>
    </Card>
  );

  const handleViewModeChange = (event, newMode) => {
    if (newMode !== null) {
      setViewMode(newMode);
    }
  };

  const handleEventClick = (info) => {
    setSelectedEvent(info.event.extendedProps);
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedEvent(null);
  };

  const rendertimestamp = () => {
    // แปลงข้อมูล timestamp เป็น events สำหรับ FullCalendar
    const events =
      timestamp?.rows?.map((item) => {
        const hasOT = item.otRequests;
        return {
          id: item._id,
          title: 'ทำงานปกติ',
          start: item.checkIn,
          end: item.checkIn,
          backgroundColor: '#4caf50',
          extendedProps: {
            checkIn: item.checkIn,
            checkOut: item.checkOut,
            otRequests: [item.otRequests],
            hasOT: hasOT,
          },
        };
      }) || [];

    const getRateChip = (rate) => {
      const rateConfig = {
        1: { label: 'X1', color: 'primary' },
        1.5: { label: 'X1.5', color: 'warning' },
        3: { label: 'X3', color: 'error' },
      };
      const config = rateConfig[rate] || rateConfig[1];
      return (
        <Chip
          label={config.label}
          color={config.color}
          size="small"
          sx={{ fontWeight: 600 }}
        />
      );
    };

    const renderListView = () => {
      if (!timestamp?.rows || timestamp.rows.length === 0) {
        return (
          <Box sx={{ p: 4, textAlign: 'center' }}>
            <Typography variant="body2" color="text.secondary">
              ไม่มีข้อมูลการลงเวลา
            </Typography>
          </Box>
        );
      }

      return (
        <List sx={{ maxHeight: 500, overflow: 'auto' }}>
          {timestamp.rows.map((item, index) => (
            <ListItem
              key={index}
              sx={{
                borderBottom: '1px solid',
                borderColor: 'divider',
                '&:hover': {
                  bgcolor: 'action.hover',
                },
                flexDirection: 'column',
                alignItems: 'flex-start',
                py: 2,
              }}
            >
              <Grid container spacing={2} alignItems="center">
                <Grid item xs={12} sm={3}>
                  <Typography variant="body2" fontWeight={600}>
                    {dayjs(item.checkIn).format('DD MMM YYYY')}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {dayjs(item.checkIn).format('dddd')}
                  </Typography>
                </Grid>
                <Grid item xs={6} sm={3}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                    <LoginIcon fontSize="small" color="success" />
                    <Box>
                      <Typography variant="caption" color="text.secondary">
                        Check In
                      </Typography>
                      <Typography variant="body2" fontWeight={600}>
                        {item.checkIn
                          ? dayjs(item.checkIn).format('HH:mm')
                          : '-'}
                      </Typography>
                    </Box>
                  </Box>
                </Grid>
                <Grid item xs={6} sm={3}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                    <LogoutIcon fontSize="small" color="error" />
                    <Box>
                      <Typography variant="caption" color="text.secondary">
                        Check Out
                      </Typography>
                      <Typography variant="body2" fontWeight={600}>
                        {item.checkOut
                          ? dayjs(item.checkOut).format('HH:mm')
                          : '-'}
                      </Typography>
                    </Box>
                  </Box>
                </Grid>
                <Grid item xs={12} sm={3}>
                  <Chip
                    label={
                      item.checkOut
                        ? 'เช็คอินและเช็คเอาท์'
                        : 'เช็คอินอย่างเดียว'
                    }
                    color={item.checkOut ? 'success' : 'warning'}
                    size="small"
                    sx={{ width: '100%' }}
                  />
                </Grid>
              </Grid>

              {/* แสดงรายละเอียด OT */}
              {item.otRequests && item.otRequests.length > 0 && (
                <Box sx={{ mt: 2, width: '100%' }}>
                  <Divider sx={{ mb: 1.5 }} />
                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 1,
                      mb: 1,
                    }}
                  >
                    <OTIcon fontSize="small" color="warning" />
                    <Typography
                      variant="subtitle2"
                      fontWeight={600}
                      color="warning.main"
                    >
                      รายการ OT
                    </Typography>
                  </Box>
                  <Stack spacing={1}>
                    {item.otRequests.map((ot, otIndex) => (
                      <Box
                        key={otIndex}
                        sx={{
                          p: 1.5,
                          bgcolor: 'grey.50',
                          borderRadius: 1,
                          border: '1px solid',
                          borderColor: 'divider',
                        }}
                      >
                        <Grid container spacing={1.5} alignItems="center">
                          <Grid item xs={12} sm={6}>
                            <Stack
                              direction="row"
                              spacing={1}
                              alignItems="center"
                            >
                              <Typography
                                variant="caption"
                                color="text.secondary"
                              >
                                เวลา OT:
                              </Typography>
                              <Typography variant="body2" fontWeight={600}>
                                {dayjs(ot.startTime).format('HH:mm')} -{' '}
                                {dayjs(ot.endTime).format('HH:mm')}
                              </Typography>
                            </Stack>
                          </Grid>
                          <Grid item xs={6} sm={3}>
                            <Stack
                              direction="row"
                              spacing={1}
                              alignItems="center"
                            >
                              <Typography
                                variant="caption"
                                color="text.secondary"
                              >
                                ชั่วโมง:
                              </Typography>
                              <Typography variant="body2" fontWeight={600}>
                                {ot.total_hours?.toFixed(1) || 0} ชม.
                              </Typography>
                            </Stack>
                          </Grid>
                          <Grid item xs={6} sm={3}>
                            <Stack
                              direction="row"
                              spacing={1}
                              alignItems="center"
                            >
                              <Typography
                                variant="caption"
                                color="text.secondary"
                              >
                                อัตรา:
                              </Typography>
                              {getRateChip(ot.rate)}
                            </Stack>
                          </Grid>
                          {ot.description && (
                            <Grid item xs={12}>
                              <Typography
                                variant="caption"
                                color="text.secondary"
                              >
                                รายละเอียด: {ot.description}
                              </Typography>
                            </Grid>
                          )}
                          {ot.status && (
                            <Grid item xs={12}>
                              <Chip
                                label={ot.status}
                                size="small"
                                color={
                                  ot.status === 'APPROVED'
                                    ? 'success'
                                    : ot.status === 'PENDING'
                                    ? 'warning'
                                    : 'error'
                                }
                              />
                            </Grid>
                          )}
                        </Grid>
                      </Box>
                    ))}
                  </Stack>
                </Box>
              )}
            </ListItem>
          ))}
        </List>
      );
    };

    return (
      <Card className="h-full">
        {/* Header */}
        <Box className="p-4 border-b">
          <Box className="flex items-center justify-between flex-wrap gap-2">
            <Box className="flex items-center gap-2">
              <CalendarIcon color="primary" />
              <Typography variant="h6" className="font-bold">
                ปฏิทินการลงเวลา
              </Typography>
            </Box>
            <ToggleButtonGroup
              value={viewMode}
              exclusive
              onChange={handleViewModeChange}
              size="small"
            >
              <ToggleButton value="calendar">
                <CalendarIcon fontSize="small" />
              </ToggleButton>
              <ToggleButton value="list">
                <ViewListIcon fontSize="small" />
              </ToggleButton>
            </ToggleButtonGroup>
          </Box>
        </Box>

        {/* Content */}
        <Box className="p-4">
          {viewMode === 'calendar' ? (
            <Box sx={{ '& .fc': { fontFamily: 'inherit' } }}>
              <FullCalendar
                plugins={[dayGridPlugin, interactionPlugin]}
                initialView="dayGridMonth"
                locale="th"
                headerToolbar={{
                  left: 'prev,next today',
                  center: 'title',
                  right: 'dayGridMonth,dayGridWeek',
                }}
                events={events}
                eventClick={handleEventClick}
                height="auto"
                buttonText={{
                  today: 'วันนี้',
                  month: 'เดือน',
                  week: 'สัปดาห์',
                }}
                dayHeaderFormat={{ weekday: 'short' }}
              />
            </Box>
          ) : (
            renderListView()
          )}
        </Box>

        {/* Event Detail Dialog */}
        <Dialog
          open={openDialog}
          onClose={handleCloseDialog}
          maxWidth="sm"
          fullWidth
        >
          <DialogTitle>
            <Box
              sx={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
              }}
            >
              <Typography variant="h6" fontWeight={600}>
                รายละเอียดการลงเวลา
              </Typography>
              <IconButton onClick={handleCloseDialog} size="small">
                <CloseIcon />
              </IconButton>
            </Box>
          </DialogTitle>
          <DialogContent dividers>
            {selectedEvent && (
              <Stack spacing={2}>
                <Grid container spacing={2}>
                  <Grid item xs={6}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      <LoginIcon fontSize="small" color="success" />
                      <Box>
                        <Typography variant="caption" color="text.secondary">
                          Check In
                        </Typography>
                        <Typography variant="body2" fontWeight={600}>
                          {dayjs(selectedEvent.checkIn).format(
                            'DD/MM/YYYY HH:mm',
                          )}
                        </Typography>
                      </Box>
                    </Box>
                  </Grid>
                  <Grid item xs={6}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      <LogoutIcon fontSize="small" color="error" />
                      <Box>
                        <Typography variant="caption" color="text.secondary">
                          Check Out
                        </Typography>
                        <Typography variant="body2" fontWeight={600}>
                          {selectedEvent.checkOut
                            ? dayjs(selectedEvent.checkOut).format(
                                'DD/MM/YYYY HH:mm',
                              )
                            : '-'}
                        </Typography>
                      </Box>
                    </Box>
                  </Grid>
                </Grid>

                {selectedEvent.hasOT && selectedEvent.otRequests && (
                  <>
                    <Divider />
                    <Box>
                      <Box
                        sx={{
                          display: 'flex',
                          alignItems: 'center',
                          gap: 1,
                          mb: 2,
                        }}
                      >
                        <OTIcon fontSize="small" color="warning" />
                        <Typography
                          variant="subtitle2"
                          fontWeight={600}
                          color="warning.main"
                        >
                          รายการ OT
                        </Typography>
                      </Box>
                      <Stack spacing={1.5}>
                        {selectedEvent.otRequests.map((ot, otIndex) => (
                          <Box
                            key={otIndex}
                            sx={{
                              p: 2,
                              bgcolor: 'grey.50',
                              borderRadius: 1,
                              border: '1px solid',
                              borderColor: 'divider',
                            }}
                          >
                            <Grid container spacing={1.5}>
                              <Grid item xs={12}>
                                <Stack
                                  direction="row"
                                  spacing={1}
                                  alignItems="center"
                                >
                                  <Typography
                                    variant="caption"
                                    color="text.secondary"
                                  >
                                    เวลา OT:
                                  </Typography>
                                  <Typography variant="body2" fontWeight={600}>
                                    {dayjs(ot.startTime).format('HH:mm')} -{' '}
                                    {dayjs(ot.endTime).format('HH:mm')}
                                  </Typography>
                                </Stack>
                              </Grid>
                              <Grid item xs={6}>
                                <Stack
                                  direction="row"
                                  spacing={1}
                                  alignItems="center"
                                >
                                  <Typography
                                    variant="caption"
                                    color="text.secondary"
                                  >
                                    ชั่วโมง:
                                  </Typography>
                                  <Typography variant="body2" fontWeight={600}>
                                    {ot.total_hours?.toFixed(1) || 0} ชม.
                                  </Typography>
                                </Stack>
                              </Grid>
                              <Grid item xs={6}>
                                <Stack
                                  direction="row"
                                  spacing={1}
                                  alignItems="center"
                                >
                                  <Typography
                                    variant="caption"
                                    color="text.secondary"
                                  >
                                    อัตรา:
                                  </Typography>
                                  {getRateChip(ot.rate)}
                                </Stack>
                              </Grid>
                              {ot.description && (
                                <Grid item xs={12}>
                                  <Typography
                                    variant="caption"
                                    color="text.secondary"
                                  >
                                    รายละเอียด:
                                  </Typography>
                                  <Typography variant="body2">
                                    {ot.description}
                                  </Typography>
                                </Grid>
                              )}
                              {ot.status && (
                                <Grid item xs={12}>
                                  <Chip
                                    label={ot.status}
                                    size="small"
                                    color={
                                      ot.status === 'APPROVE'
                                        ? 'success'
                                        : ot.status === 'PENDING'
                                        ? 'warning'
                                        : 'error'
                                    }
                                  />
                                </Grid>
                              )}
                            </Grid>
                          </Box>
                        ))}
                      </Stack>
                    </Box>
                  </>
                )}
              </Stack>
            )}
          </DialogContent>
          <DialogActions>
            <Button onClick={handleCloseDialog}>ปิด</Button>
          </DialogActions>
        </Dialog>
      </Card>
    );
  };

  const renderProject = () => (
    <Card className="h-full">
      <Box className="p-4 border-b">
        <Box className="flex items-center gap-2">
          <ProjectIcon color="primary" />
          <Typography variant="h6" className="font-bold">
            โครงการ
          </Typography>
        </Box>
      </Box>
      <Box sx={{ maxHeight: 400 }} className="overflow-auto p-4">
        {project?.rows?.map((item, index) => (
          <Box
            key={index}
            className="p-3 mb-2 rounded-lg border hover:bg-gray-50 transition-colors"
          >
            <Typography variant="subtitle1" className="font-bold mb-2">
              {item.project_number} - {item.name}
            </Typography>
            <Grid container spacing={2}>
              <Grid item xs={6}>
                <Typography variant="caption" color="textSecondary">
                  สถานะ
                </Typography>
                <Box className="mt-1">
                  <Chip
                    size="small"
                    color={item.status === 'ACTIVE' ? 'success' : 'default'}
                    label={item.status}
                  />
                </Box>
              </Grid>
              <Grid item xs={6}>
                <Typography variant="caption" color="textSecondary">
                  วันที่เริ่ม
                </Typography>
                <Typography className="font-medium">
                  {dayjs(item.start_date).format('DD/MM/YYYY')}
                </Typography>
              </Grid>
            </Grid>
          </Box>
        ))}
      </Box>
    </Card>
  );

  return (
    <div>
      {renderTitle()}
      {renderDetail()}
      <Grid container spacing={2}>
        <Grid item xs={12} md={6}>
          {rendertimestamp()}
        </Grid>
        <Grid item xs={12} md={6}>
          {renderProject()}
        </Grid>
      </Grid>
    </div>
  );
}
